import{L as e,b as t,x as n}from"./vue-BDJHnCxa.js";import{t as r}from"./app-DcQgDZmH.js";var i=JSON.parse(`{"path":"/blog/l603glcu/","title":"wsl_migration_guide | Blog","lang":"zh-CN","frontmatter":{"title":"wsl_migration_guide","createTime":"2025/11/20 15:37:44","permalink":"/blog/l603glcu/","description":"WSL 发行版的文件（ext4.vhdx）会占用大量的 C 盘空间。本文档将指导您如何安全、完整地将您的 Ubuntu 发行版迁移到 D 盘，并解决导入后默认用户为 root 的问题。 准备工作 在开始之前,请在 PowerShell 中执行以下命令,确认您的发行版名称和状态: 提示 本文档以您的发行版名称 Ubuntu 和用户名为 ub001 作为示...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"wsl_migration_guide\\",\\"image\\":[\\"\\"],\\"dateModified\\":null,\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://powersen.cn/blog/l603glcu/"}],["meta",{"property":"og:site_name","content":"Powersen"}],["meta",{"property":"og:title","content":"wsl_migration_guide"}],["meta",{"property":"og:description","content":"WSL 发行版的文件（ext4.vhdx）会占用大量的 C 盘空间。本文档将指导您如何安全、完整地将您的 Ubuntu 发行版迁移到 D 盘，并解决导入后默认用户为 root 的问题。 准备工作 在开始之前,请在 PowerShell 中执行以下命令,确认您的发行版名称和状态: 提示 本文档以您的发行版名称 Ubuntu 和用户名为 ub001 作为示..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}]]},"readingTime":{"minutes":3.67,"words":1100},"git":{"createdTime":1779970460000},"autoDesc":true,"filePathRelative":"blog/5.其他/wsl_migration_guide.md","headers":[],"categoryList":[{"id":"9319d1","sort":5,"name":"其他"}]}`),a={name:`wsl_migration_guide.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<p>WSL 发行版的文件（<code>ext4.vhdx</code>）会占用大量的 C 盘空间。本文档将指导您如何安全、完整地将您的 Ubuntu 发行版迁移到 D 盘，并解决导入后默认用户为 <code>root</code> 的问题。</p><h2 id="准备工作" tabindex="-1"><a class="header-anchor" href="#准备工作"><span>准备工作</span></a></h2><p>在开始之前,请在 PowerShell 中执行以下命令,确认您的发行版名称和状态:</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">l </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">v</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">提示</p><p>本文档以您的发行版名称 <code>Ubuntu</code> 和用户名为 <code>ub001</code> 作为示例。请在执行命令时替换为您的实际名称。</p></div><h2 id="第一步-数据迁移-导出与导入" tabindex="-1"><a class="header-anchor" href="#第一步-数据迁移-导出与导入"><span>第一步:数据迁移(导出与导入)</span></a></h2><p>整个迁移过程通过 <strong>导出</strong> C 盘数据,<strong>注销</strong> C 盘发行版,然后 <strong>导入</strong> 到 D 盘来实现。</p><h3 id="_1-1-终止-wsl-实例" tabindex="-1"><a class="header-anchor" href="#_1-1-终止-wsl-实例"><span>1.1 终止 WSL 实例</span></a></h3><p>确保您要迁移的发行版已停止运行。</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 如果发行版正在运行,必须先终止</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">terminate Ubuntu</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-导出发行版文件系统" tabindex="-1"><a class="header-anchor" href="#_1-2-导出发行版文件系统"><span>1.2 导出发行版文件系统</span></a></h3><p>将 <code>Ubuntu</code> 的文件系统完整导出为一个 <code>.tar</code> 归档文件到 D 盘的临时备份目录。</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 1. 创建备份目录</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">mkdir D:\\WSL_Backup</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 2. 执行导出操作(这个过程可能需要几分钟到几十分钟)</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">export Ubuntu </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">D:\\WSL_Backup\\ubuntu_export.tar</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container note"><p class="hint-container-title">注意</p><p>导出成功后,请在文件资源管理器中确认 <code>D:\\WSL_Backup</code> 下已生成 <code>ubuntu_export.tar</code> 文件。</p></div><h3 id="_1-3-注销原有发行版" tabindex="-1"><a class="header-anchor" href="#_1-3-注销原有发行版"><span>1.3 注销原有发行版</span></a></h3><p>成功导出后,您可以安全地注销 C 盘上的原有发行版,以释放 C 盘空间。</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">unregister Ubuntu</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="hint-container caution"><p class="hint-container-title">警告</p><p>此操作会删除 C 盘上发行版的所有数据。请务必确认导出文件已成功生成。</p></div><h3 id="_1-4-导入到-d-盘的新位置" tabindex="-1"><a class="header-anchor" href="#_1-4-导入到-d-盘的新位置"><span>1.4 导入到 D 盘的新位置</span></a></h3><p>现在,将 <code>.tar</code> 文件导入到 D 盘上指定的安装目录,并确保它仍然使用 <strong>WSL 2</strong> 架构。</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 1. 创建新的安装目录</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">mkdir D:\\WSL_Distros\\Ubuntu</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 2. 导入发行版到 D 盘</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">import Ubuntu </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">D:\\WSL_Distros\\Ubuntu</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">D:\\WSL_Backup\\ubuntu_export.tar</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> --</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">version </span><span style="--shiki-light:#2F798A;--shiki-dark:#4C9A91;">2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">验证</p><p>运行 <code>wsl -l -v</code> 确认 <code>Ubuntu</code> 状态为 <code>Stopped</code>,版本为 <code>2</code>。您现在可以在 <code>D:\\WSL_Distros\\Ubuntu</code> 目录下找到新的磁盘文件 <code>ext4.vhdx</code>。</p></div><h2 id="第二步-配置默认用户-解决-root-登录" tabindex="-1"><a class="header-anchor" href="#第二步-配置默认用户-解决-root-登录"><span>第二步:配置默认用户(解决 Root 登录)</span></a></h2><p>通过 <code>--import</code> 导入的发行版默认会以 <code>root</code> 用户身份启动。由于 PowerShell 配置注册表遇到兼容性问题,我们采用更可靠的 <strong><code>/etc/wsl.conf</code> 配置文件</strong>来设置您的默认用户 <code>ub001</code>。</p><h3 id="_2-1-启动-wsl-并编辑配置文件" tabindex="-1"><a class="header-anchor" href="#_2-1-启动-wsl-并编辑配置文件"><span>2.1 启动 WSL 并编辑配置文件</span></a></h3><p><strong>① 启动 WSL(将以 root 身份登录):</strong></p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>② 打开或创建 <code>/etc/wsl.conf</code> 文件:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 使用 vi 编辑器</span></span>
<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">vi</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> /etc/wsl.conf</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>③ 添加默认用户配置:</strong></p><p>在 vi 中按 <code>i</code> 键进入插入模式,并粘贴以下内容:</p><div class="language-ini line-numbers-mode" data-highlighter="shiki" data-ext="ini" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-ini"><span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">[</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">user</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">]</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">default</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">ub001</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">提示</p><p>请将 <code>ub001</code> 替换为您在 Ubuntu 中的实际用户名。</p></div><p><strong>④ 保存并退出:</strong></p><p>按 <code>Esc</code> 键退出插入模式,然后输入 <code>:wq</code> 并按 <code>Enter</code>。</p><h3 id="_2-2-应用配置并验证" tabindex="-1"><a class="header-anchor" href="#_2-2-应用配置并验证"><span>2.2 应用配置并验证</span></a></h3><p>配置文件的更改需要终止实例才能生效。</p><p><strong>① 退出 Linux Shell:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">exit</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>② 终止实例:</strong></p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">terminate Ubuntu</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>③ 重新启动 WSL 并验证:</strong></p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果配置成功,您的提示符将显示:</p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">ub001@Yusen:~$</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="第三步-清理工作-可选" tabindex="-1"><a class="header-anchor" href="#第三步-清理工作-可选"><span>第三步:清理工作(可选)</span></a></h2><p>迁移成功并确认 <code>ub001</code> 登录正常后,您可以删除之前导出的 <code>.tar</code> 备份文件,以释放 D 盘空间。</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 删除备份文件和目录</span></span>
<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">Remove-Item</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> D:\\WSL_Backup </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">Recurse </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">Force</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container important"><p class="hint-container-title">完成</p><p>恭喜! 您已经成功将 WSL Ubuntu 发行版从 C 盘迁移到 D 盘,并配置了正确的默认用户。</p></div><h2 id="常见问题" tabindex="-1"><a class="header-anchor" href="#常见问题"><span>常见问题</span></a></h2><details class="hint-container details"><summary>为什么导入后默认是 root 用户?</summary><p>使用 <code>wsl --import</code> 导入的发行版不会保留原有的默认用户配置,系统会默认使用 root 用户登录。需要通过 <code>/etc/wsl.conf</code> 文件手动指定默认用户。</p></details><details class="hint-container details"><summary>可以不注销原发行版直接导入吗?</summary><p>可以,但这样会同时存在两个发行版(不同的名称),C 盘空间不会被释放。只有注销原发行版才能真正释放 C 盘空间。</p></details><details class="hint-container details"><summary>迁移后原来的配置和文件还在吗?</summary><p>是的,迁移过程会完整保留所有文件、配置和已安装的软件包,就像是把整个文件系统&quot;搬家&quot;到了新位置。</p></details><h2 id="相关链接" tabindex="-1"><a class="header-anchor" href="#相关链接"><span>相关链接</span></a></h2><ul><li><a href="https://docs.microsoft.com/zh-cn/windows/wsl/" target="_blank" rel="noopener noreferrer">WSL 官方文档</a></li><li><a href="https://docs.microsoft.com/zh-cn/windows/wsl/basic-commands" target="_blank" rel="noopener noreferrer">WSL 基本命令参考</a></li><li><a href="https://docs.microsoft.com/zh-cn/windows/wsl/wsl-config" target="_blank" rel="noopener noreferrer">WSL 配置文件说明</a></li></ul>`,55)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};